/* office — the fractal site map's pure engine.
 *
 * mino.mobi/office is an "office of offices": every surface is a desk in a room
 * whose back wall is papered with framed posters, and every poster is itself a
 * miniature office — a desk with a wall of posters — for a child surface. You
 * scroll-zoom through the Droste stack; the desk's monitor opens the live site.
 *
 * This module is the deterministic, DOM-free half: it turns the flat taxonomy
 * (office/surfaces.json, generated by scripts/build-office.mjs from index.html's
 * PROJECTS array) into a tree, lays out each wall's posters, and carries the
 * seeded PRNG + palette the renderer paints with. Kept pure so it unit-tests in
 * plain node (office/engine.selftest.mjs) — the renderer (office/office.js)
 * imports the same functions, so the wall you test is the wall you see.
 *
 * Attaches to globalThis.OFFICE (browser + node) and also ES-exports. */

(function () {
  "use strict";
  const NS = (typeof window !== "undefined") ? window : globalThis;
  const O = NS.OFFICE = NS.OFFICE || {};

  // ── seeded PRNG (xmur3 hash → mulberry32), the repo's borges idiom ──────────
  function hashStr(str) {
    let h = 1779033703 ^ str.length;
    for (let i = 0; i < str.length; i++) {
      h = Math.imul(h ^ str.charCodeAt(i), 3432918353);
      h = (h << 13) | (h >>> 19);
    }
    return function () {
      h = Math.imul(h ^ (h >>> 16), 2246822507);
      h = Math.imul(h ^ (h >>> 13), 3266489909);
      h ^= h >>> 16;
      return h >>> 0;
    };
  }
  function mulberry32(a) {
    return function () {
      a |= 0; a = (a + 0x6D2B79F5) | 0;
      let t = Math.imul(a ^ (a >>> 15), 1 | a);
      t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
      return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    };
  }
  // A stable [0,1) stream keyed by any string — every office's jitter, clutter,
  // and wall grain is reproducible from its id.
  function rngFor(key) { return mulberry32(hashStr(String(key))()); }

  // ── palette ─────────────────────────────────────────────────────────────────
  // One accent per top-level category; wings inherit their surface's category.
  // wall/wall2 are the back-wall gradient, floor the boards, accent the light.
  const PALETTE = {
    root:    { name: "lobby",   accent: "#e8c979", wall: "#2a2620", wall2: "#161310", floor: "#1c1712" },
    bluesky: { name: "bluesky", accent: "#5aa9ff", wall: "#1d2836", wall2: "#0e1620", floor: "#131b25" },
    games:   { name: "games",   accent: "#d073ff", wall: "#2b1f33", wall2: "#160f1c", floor: "#1d1424" },
    tools:   { name: "tools",   accent: "#f2b53d", wall: "#31281a", wall2: "#1a140b", floor: "#221a10" },
    data:    { name: "data",    accent: "#3ec7a8", wall: "#193029", wall2: "#0d1a16", floor: "#122320" },
    work:    { name: "work",    accent: "#ff8a5c", wall: "#332019", wall2: "#1b0f0a", floor: "#241511" },
    misc:    { name: "misc",    accent: "#9aa4b2", wall: "#242830", wall2: "#12151a", floor: "#181b21" },
  };
  function paletteFor(cat) { return PALETTE[cat] || PALETTE.misc; }

  // age → the warmth of the desk lamp (recency read as heat).
  const AGE_HEAT = { hot: 1.0, warm: 0.55, cold: 0.22 };
  function heatFor(age) { return AGE_HEAT[age] != null ? AGE_HEAT[age] : 0.4; }

  // ── tree building ────────────────────────────────────────────────────────────
  // Synthesises: root (mino.mobi) → one desk per category → that category's
  // top-level surfaces → their wings (nodes carrying a `parent`). Wings inherit
  // their surface's category regardless of their own tag, so a branch stays one
  // colour as you dive.
  function buildTree(data) {
    const cats = data.categories || [];
    const raw = data.nodes || [];
    const byId = new Map();
    for (const n of raw) {
      byId.set(n.id, {
        id: n.id, name: n.name, url: n.url || null,
        cat: n.cat || "misc", commits: n.commits || 0, age: n.age || "cold",
        parent: n.parent || null, children: [],
      });
    }
    // A `parent` value in the data is a NAME (index.html uses `p:'rite'`), so
    // resolve it to whichever node carries that name.
    const byName = new Map();
    for (const n of byId.values()) if (!byName.has(n.name)) byName.set(n.name, n);

    // `parent` is a node id (filesystem-discovered nodes: "rind/ops") or, for the
    // curated PROJECTS entries, a bare name that doubles as the parent's id.
    const tops = [];
    for (const n of byId.values()) {
      const p = n.parent && (byId.get(n.parent) || byName.get(n.parent));
      if (p && p !== n) { n.cat = p.cat; p.children.push(n); }
      else tops.push(n);
    }

    // category desks
    const catOrder = cats.length ? cats : [...new Set(tops.map((t) => t.cat))];
    const catNodes = new Map();
    for (const c of catOrder) {
      catNodes.set(c, {
        id: "__cat_" + c, name: paletteFor(c).name, url: (data.root && data.root.url) || "https://mino.mobi",
        cat: c, commits: 0, age: "hot", parent: "__root", children: [], isCategory: true,
      });
    }
    for (const t of tops) {
      let cn = catNodes.get(t.cat);
      if (!cn) { cn = catNodes.get("misc") || [...catNodes.values()][0]; }
      if (cn) cn.children.push(t);
    }

    const root = {
      id: "__root",
      name: (data.root && data.root.name) || "mino.mobi",
      url: (data.root && data.root.url) || "https://mino.mobi",
      cat: "root", commits: 0, age: "hot", parent: null, isRoot: true,
      children: [...catNodes.values()].filter((c) => c.children.length),
    };

    // Order every wall by prominence (commits desc, then name) and roll up a
    // recursive weight + descendant count for sizing / labels. Back-link parents.
    const finalize = (node, parent, depth) => {
      node.parentNode = parent || null;
      node.depth = depth;
      node.children.sort((a, b) => (b.commits - a.commits) || a.name.localeCompare(b.name));
      let w = Math.max(1, node.commits), count = 0;
      for (let i = 0; i < node.children.length; i++) {
        const c = node.children[i];
        c.childIndex = i;
        finalize(c, node, depth + 1);
        w += c.weight; count += 1 + c.descendants;
      }
      node.weight = w;
      node.descendants = count;
      return node;
    };
    finalize(root, null, 0);
    return root;
  }

  // ── wall layout ───────────────────────────────────────────────────────────────
  // Places `n` child posters on the back wall as a centred grid. Poster rects are
  // returned in the room's unit box [0,1]×[0,1]; the renderer scales them to the
  // room's on-screen rect. Posters share the room's aspect so a dive into one is
  // self-similar (the Droste seam). The wall occupies the room minus a margin and
  // minus the desk band across the bottom.
  const WALL = { top: 0.05, side: 0.045, bottom: 0.34, gap: 0.16 };

  function gridDims(n) {
    if (n <= 0) return { cols: 0, rows: 0 };
    const cols = Math.max(1, Math.ceil(Math.sqrt(n)));
    const rows = Math.max(1, Math.ceil(n / cols));
    return { cols, rows };
  }

  function layoutWall(n) {
    const rects = [];
    if (n <= 0) return rects;
    const { cols, rows } = gridDims(n);
    const areaX = WALL.side, areaY = WALL.top;
    const areaW = 1 - WALL.side * 2;
    const areaH = 1 - WALL.top - WALL.bottom;
    const cellW = areaW / cols;
    const cellH = areaH / rows;
    const padX = cellW * WALL.gap * 0.5;
    const padY = cellH * WALL.gap * 0.5;
    for (let i = 0; i < n; i++) {
      const r = Math.floor(i / cols);
      const c = i % cols;
      // centre the (possibly short) last row
      const inRow = (r === rows - 1) ? (n - r * cols) : cols;
      const rowOffset = (cols - inRow) * cellW * 0.5;
      const x = areaX + rowOffset + c * cellW + padX;
      const y = areaY + r * cellH + padY;
      rects.push({ x, y, w: cellW - padX * 2, h: cellH - padY * 2, row: r, col: c });
    }
    return rects;
  }

  // path from root → node (inclusive), for breadcrumbs.
  function pathTo(node) {
    const out = [];
    let c = node;
    while (c) { out.unshift(c); c = c.parentNode; }
    return out;
  }

  Object.assign(O, {
    hashStr, mulberry32, rngFor,
    PALETTE, paletteFor, heatFor,
    buildTree, gridDims, layoutWall, pathTo, WALL,
  });
})();

export const {
  hashStr, mulberry32, rngFor,
  PALETTE, paletteFor, heatFor,
  buildTree, gridDims, layoutWall, pathTo, WALL,
} = (typeof window !== "undefined" ? window : globalThis).OFFICE;
